mapper.select:
SELECT h.price_id , h.stock_cd , h.price_dt , h.open_price , h.high_price , h.low_price , h.close_price , h.volume , h.reg_dt FROM tbl_stock_price_history h INNER JOIN ( SELECT stock_cd , MAX(price_dt) AS max_price_dt FROM tbl_stock_price_history WHERE stock_cd IN
#{stockCd}
GROUP BY stock_cd ) latest ON h.stock_cd = latest.stock_cd AND h.price_dt = latest.max_price_dt

mapper.insert:
INSERT INTO tbl_stock_price_history (
     stock_cd
   , price_dt
   , open_price
   , high_price
   , low_price
   , close_price
   , volume
   , reg_dt
) VALUES (
     #{stockCd}
   , #{priceDt}
   , #{openPrice}
   , #{highPrice}
   , #{lowPrice}
   , #{closePrice}
   , #{volume}
   , NOW()
)

